UPDATE decision_nodes SET data = '{"type":"info","module":4,"title":"HCM Treatment — IVF + Calcitonin + Bisphosphonate","body":"**Step 1 — Aggressive IV Hydration (cornerstone):** [9][10]\n* **Normal saline 200-300 mL/hr** until euvolemic, then 100-150 mL/hr\n* Goal urine output >100 mL/hr\n* Most patients are profoundly volume depleted from hypercalcemia-induced nephrogenic DI\n* Avoid LR (contains calcium)\n* AVOID loop diuretics in routine cases — only use if volume overload develops; prior dogma of forced calciuresis with furosemide is not supported by evidence and can worsen depletion [10]\n\n**Step 2 — Calcitonin (rapid onset, short duration):**\n* **[Calcitonin](#/drug/calcitonin/hypercalcemia)** 4 IU/kg SC or IM q12h\n* Drops Ca by 1-2 mg/dL within 4-6 hours\n* Tachyphylaxis develops within 48-72 hours\n* Bridge while bisphosphonate takes effect\n\n**Step 3 — Antiresorptive Therapy (sustained effect):**\n\n**2022 Endocrine Society Guideline now SUGGESTS denosumab in preference to IV bisphosphonates as first-line** — more potent suppression of bone turnover, fewer infusion reactions, fewer renal adverse events, usable in CKD stage 4-5. [10] Either agent is acceptable; many centers still default to zoledronic acid based on cost and availability.\n\n**[Denosumab](#/drug/denosumab/hypercalcemia)** 120 mg SC (first-line per 2022 Endo Society):\n* RANKL inhibitor — no renal clearance required\n* Onset 24-48 hours; max effect 14-23 days; duration 4-8 weeks\n* Use in CrCl <30, bisphosphonate-refractory, or as primary first-line\n* Risk: severe hypocalcemia (monitor; replete vit D when feasible — do not delay treatment)\n\n**[Zoledronic acid](#/drug/zoledronic-acid/hypercalcemia)** 4 mg IV over 15-30 minutes (alternative first-line):\n* More potent than pamidronate\n* Onset 24-48 hours; peak effect 4-7 days; duration 4 weeks\n* Adjust dose for renal function (avoid if CrCl <30)\n* Risks: osteonecrosis of jaw (long-term), atypical femur fracture, acute kidney injury\n\n**Step 5 — Steroids (if vit-D mediated):**\n* Lymphoma, myeloma, granulomatous disease\n* [Prednisone](#/drug/prednisone/hypercalcemia) 40-60 mg PO daily\n\n**Step 6 — Hemodialysis if:**\n* Ca >18 with neuro/cardiac sx\n* Renal failure preventing IVF\n* Refractory to medical therapy","citation":[9,10],"next":"onc-hyperca-disposition","calculatorLinks":[{"id":"corrected-calcium","label":"Corrected Calcium"},{"id":"hyperca-severity","label":"Hypercalcemia Severity"}],"summary":"HCM: NS 200-300 mL/hr + calcitonin 4 IU/kg q12h (rapid bridge) + denosumab 120 SC (Endo 2022 first-line) OR zoledronic acid 4 mg IV; avoid loop diuretics"}'::jsonb
WHERE id = 'onc-hyperca-treat' AND tree_id = 'oncological-emergencies';

